VALUES
  ('social-worker-moex-07170', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一群人非常強烈的投入在一個高度凝聚力的團體，其成員的想法經常是全體一致，這種現象稱為：', '["團體凝聚", "團體動力", "團體思考", "團體依賴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07171', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區能力建構（community capacity building）的觀點，其敘述何者錯誤？', '["社區能力是一個社區之各項「資產」或「屬性」的總和", "社區資產的類型不包括政治的資產，以免產生派系紛爭", "一個社區的資產是否能夠有效使用，端視社區的組成分子對此「資產」的運用", "社區資產是靜態的能力，社區力量則是動態的能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07172', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區工作的目標，不包括：', '["促進居民參與及解決自己的問題", "帶動社區派系力量的成長", "提升居民的社區意識", "善用社區的資源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07173', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關「面質」（Confronting）的敘述，何者錯誤？', '["面質通常適用於案主出現語言和行為不一致或是矛盾的情況下", "最好以同理的反應來與案主面質", "面質適合運用在直接服務的各個階段中，它能有效協助案主面對自己的想法", "面質容易引發案主因為被挑戰的負向情緒，所以較適合運用在社會工作者與案主專業關係建立較好的時候"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07174', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關生態系統模型中「行動系統」（action system）的敘述，何者正確？', '["係指努力改變的焦點系統，為了達到目標需要影響的人與問題", "係指社會工作者為了達成處遇目標，而需要合作的正式與非正式資源", "係指要求改變的個人及其他接受服務的受益人", "係指非志願案主不自覺的非法或危險行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07175', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「社區照顧」被視為比較符合人性的照顧方式，以下對於英國社區照顧要素的敘述何者正確？', '["去機構化是社區照顧主要目標，因此，社區內不能有任何全時照顧機構存在，才是社區照顧", "社區照顧如透過非正式、志願與民間部門提供服務，會有降低服務水準之虞", "社區照顧的服務需求，應以供給導向為主，以免找不到適當資源", "隨著人口老化和治療方式改變，機構照顧會逐漸轉移至成本較為低廉的社區照顧"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07176', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區網絡的建構，可以促成全面性的社區發展，要讓網絡關係可以維繫，但在基本前提上不包括：', '["必須建立在具有影響力的社區領導者號召上", "必須建立在公平的原則上", "必須要有實質的績效作激勵", "必須要能彈性因應目標的調整"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07177', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作已成為社會工作專業方法之一，以下敘述何者正確？', '["1929年藍尼（Robert P. Lane）報告書闡述社區工作方法", "1952年美國社會工作教育學會的課程政策聲明為社會工作三大方法之一", "社區工作也可以被視為「鉅觀實務工作」（macro practice）的一部分", "社區工作者最重要的技能是社區組織技術，不必瞭解個案與團體的知能，以免產生工作上的混淆"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07178', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於會心團體（encounter group）的敘述，何者錯誤？', '["團體活動是為了學習更複雜的技能，以達成行為改變", "由羅吉斯（Carl Rogers）於芝加哥大學發展而來", "透過密集的團體經驗，使成員獲致較佳的自我瞭解", "可算是成長團體的一種"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07179', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作模型的敘述，何者正確？', '["三個主要實施模型依其提出的先後順序是：交互模型、治療模型、社會目標模型", "交互模型工作者主要角色是「變遷媒介者」", "社會目標模型工作者主要角色是「影響者」", "治療模型工作者主要角色是「使能者」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
